  for (let i = memo.size; i <= n; i++) {
    const prev1 = memo.get(i - 1);
    const prev2 = memo.get(i - 2);

    if (prev1 === undefined || prev2 === undefined) {
      throw new Error(`Memoization state corrupted at index ${i}`);
    }

    memo.set(i, prev1 + prev2);
