class LinkedKeySet {
  private seen = new Set<string>();
  private ordered: string[] = [];

  add(key: string): void {
    if (!this.seen.has(key)) {
      this.seen.add(key);
      this.ordered.push(key);
    }
  }

  keys(): string[] {
    return this.ordered;
  }
}

