export function matrixMultiply(a: number[][], b: number[][]): number[][] {
  if (!Array.isArray(a) || !Array.isArray(b)) {
    throw new TypeError("Both arguments must be 2D arrays");
  }

  if (a.length === 0 || b.length === 0) {
    throw new RangeError("Matrices must not be empty");
  }

  const aRows = a.length;
  const aCols = a[0].length;
  const bRows = b.length;
  const bCols = b[0].length;

  if (aCols === 0 || bCols === 0) {
    throw new RangeError("Matrix rows must not be empty");
  }

  for (let i = 0; i < aRows; i++) {
    if (!Array.isArray(a[i]) || a[i].length !== aCols) {
      throw new RangeError(`Matrix A is not rectangular: row ${i} has inconsistent column count`);
    }
  }

  for (let i = 0; i < bRows; i++) {
    if (!Array.isArray(b[i]) || b[i].length !== bCols) {
      throw new RangeError(`Matrix B is not rectangular: row ${i} has inconsistent column count`);
    }
  }

  if (aCols !== bRows) {
    throw new RangeError(
      `Incompatible matrix dimensions: A has ${aCols} columns but B has ${bRows} rows`
    );
  }

  const result: number[][] = Array.from({ length: aRows }, () =>
    new Array(bCols).fill(0)
  );

  for (let i = 0; i < aRows; i++) {
    for (let j = 0; j < bCols; j++) {
      let sum = 0;
      for (let k = 0; k < aCols; k++) {
        const aVal = a[i][k];
        const bVal = b[k][j];
        if (typeof aVal !== "number" || typeof bVal !== "number") {
          throw new TypeError(`Non-numeric value encountered at A[${i}][${k}] or B[${k}][${j}]`);
        }
        if (!isFinite(aVal) || !isFinite(bVal)) {
          throw new RangeError(`Non-finite value encountered at A[${i}][${k}] or B[${k}][${j}]`);
        }
        sum += aVal * bVal;
      }
      result[i][j] = sum;
    }
  }

  return result;
}

export default matrixMultiply;

function escapeValue(value: unknown): string {
  if (value === null || value === undefined) return "";
  const str = String(value);
  if (str.includes('"') || str.includes(',') || str.includes('\n') || str.includes('\r')) {
    return `"${str.replace(/"/g, '""')}"`;
