    throw new RangeError(`Expected a non-negative integer, got: ${n}`);
  }
  if (n > 1000) {
    throw new RangeError(`n exceeds supported maximum of 1000, got: ${n}`);
  }

  if (n === 0) return 0n;
  if (n === 1) return 1n;

  if (memo.has(n)) {
    return memo.get(n)!;
  }

  // Iterative approach to avoid call stack overflow for large n,
  // while still populating the memo cache for subsequent calls.
  let lo = memo.get(0) ?? 0n;
  let hi = memo.get(1) ?? 1n;

  // Find the highest already-memoized value below n to resume from.
  let start = 1;
  for (let i = n - 1; i >= 2; i--) {
    if (memo.has(i) && memo.has(i - 1)) {
      lo = memo.get(i - 1)!;
      hi = memo.get(i)!;
      start = i;
      break;
    }
  }

  for (let i = start + 1; i <= n; i++) {
    const next = lo + hi;
    lo = hi;
    hi = next;
    memo.set(i, hi);
  }

  return memo.get(n)!;
}

