function escapeField(value: unknown): string {
  if (value === null || value === undefined) {
    return "";
  }

  const str = String(value);

  // Per RFC 4180: enclose in double-quotes if the field contains
  // a comma, double-quote, newline, or carriage return.
  if (str.includes('"') || str.includes(",") || str.includes("\n") || str.includes("\r")) {
    // Escape existing double-quotes by doubling them, then wrap the whole field.
    return `"${str.replace(/"/g, '""')}"`;
  }

  return str;
}

export default function formatCSV(rows: Record<string, unknown>[]): string {
  if (!Array.isArray(rows) || rows.length === 0) {
    return "";
  }

  // Derive headers from the first object's keys.
  // Null/non-object rows are a real risk — guard against them.
  const firstRow = rows[0];
  if (firstRow === null || typeof firstRow !== "object" || Array.isArray(firstRow)) {
    return "";
  }

  const headers = Object.keys(firstRow);

  if (headers.length === 0) {
    return "";
  }

  const headerLine = headers.map(escapeField).join(",");

  const dataLines = rows.map((row, index) => {
    // Defensive: if a subsequent row is not an object, emit empty fields.
    const safeRow: Record<string, unknown> =
      row !== null && typeof row === "object" && !Array.isArray(row)
        ? (row as Record<string, unknown>)
        : {};

    return headers.map((key) => escapeField(safeRow[key])).join(",");
  });

  return [headerLine, ...dataLines].join("\n");
}

